def has_breezeway_window(manufacturer, model, year):
    breezeway_models = {
        'Mercury': {
            'Turnpike Cruiser': (1957, 1958),
            'Park Lane': (1963, 1968),
            'Montclair': (1963, 1968),
            'Monterey': (1963, 1968),
            'S-55': (1963, 1966),
        },
        'Lincoln': {
            'Continental Mark III': (1958, 1960),
            'Continental Mark IV': (1958, 1960),
            'Continental Mark V': (1958, 1960),
        }
    }
    if manufacturer in breezeway_models and model in breezeway_models[manufacturer]:
        start_year, end_year = breezeway_models[manufacturer][model]
        return start_year <= year <= end_year
    return False

# Example usage:
print(has_breezeway_window('Mercury', 'Park Lane', 1965))  # Output: True
print(has_breezeway_window('Lincoln', 'Continental Mark V', 1961))  # Output: False
